package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;

import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

class Gson_GetAdapterTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void getAdapter_withClass_returnsNonNullTypeAdapter() {
    TypeAdapter<String> adapter = gson.getAdapter(String.class);
    assertNotNull(adapter);
  }

  @Test
  void getAdapter_withPrimitiveClass_returnsNonNullTypeAdapter() {
    TypeAdapter<Integer> adapter = gson.getAdapter(int.class);
    assertNotNull(adapter);
  }

  @Test
  void getAdapter_withArrayClass_returnsNonNullTypeAdapter() {
    TypeAdapter<int[]> adapter = gson.getAdapter(int[].class);
    assertNotNull(adapter);
  }

  @Test
  void getAdapter_withCustomClass_returnsNonNullTypeAdapter() {
    class Custom {}
    TypeAdapter<Custom> adapter = gson.getAdapter(Custom.class);
    assertNotNull(adapter);
  }

  @Test
  void getAdapter_withNullClass_throwsNullPointerException() {
    assertThrows(NullPointerException.class, () -> gson.getAdapter((Class<?>) null));
  }

  @Test
  void getAdapter_reflectiveInvocation_returnsSameAdapter() throws Exception {
    Class<String> clazz = String.class;
    Method method = Gson.class.getMethod("getAdapter", TypeToken.class);
    @SuppressWarnings("unchecked")
    TypeAdapter<String> adapter = (TypeAdapter<String>) method.invoke(gson, TypeToken.get(clazz));
    assertNotNull(adapter);
  }
}
